import signal, os, time, threading

class FakeProvider:
    def force_flush(self): print("FLUSHED", flush=True)
    def shutdown(self): print("SHUTDOWN", flush=True)

def _safe(fn):
    try: fn()
    except Exception: pass

provider = FakeProvider()

# replicate _install_flush_on_exit handler logic
prior = signal.getsignal(signal.SIGTERM)
def _handler(signum, frame):
    _safe(provider.force_flush)
    _safe(getattr(provider, "shutdown", lambda: None))
    if callable(prior):
        prior(signum, frame)
signal.signal(signal.SIGTERM, _handler)

pid = os.getpid()
os.kill(pid, signal.SIGTERM)
# if we reach here, SIGTERM did NOT terminate the process
print("STILL ALIVE AFTER SIGTERM", flush=True)
EOF
